import { Link } from "react-router-dom";

function MatchCard({ match }) {
  const teamAPlayers = match.players?.filter(p => p.team === match.teamA) || [];
  const teamBPlayers = match.players?.filter(p => p.team === match.teamB) || [];

  const getTopPlayer = (players) => {
    return players.length > 0
      ? players.reduce((prev, current) => 
          prev.runs > current.runs ? prev : current
        )
      : null;
  };

  const teamATop = getTopPlayer(teamAPlayers);
  const teamBTop = getTopPlayer(teamBPlayers);

  return (
    <div className="card match-card">
      <h4>{match.teamA} vs {match.teamB}</h4>
      <p className="score">{match.scoreA} | {match.scoreB}</p>
      <p>Status: <span style={{ color: match.status === 'Live' ? 'red' : '#666', fontWeight: 'bold' }}>{match.status}</span></p>

      {match.status === "Completed" && (
        <div style={{ marginBottom: '10px', padding: '8px', backgroundColor: '#f0f8ff', borderRadius: '4px' }}>
          {match.winner ? (
            <>
              <p style={{ margin: '0 0 5px 0' }}><strong>Winner:</strong> {match.winner} {match.winType && `(${match.winType}${match.winMargin ? ` ${match.winMargin}` : ""})`}</p>
              {match.manOfMatch && (
                <p style={{ margin: '0' }}><strong>Man of Match:</strong> {match.manOfMatch}</p>
              )}
            </>
          ) : (
            <p style={{ margin: '0', color: '#999' }}>Result not updated yet</p>
          )}
        </div>
      )}

      <div className="match-card-players">
        {teamATop && (
          <div className="top-player">
            <p className="player-name">{teamATop.name}</p>
            <div className="player-mini-stats">
              <span>{teamATop.runs} runs</span>
              <span>SR: {teamATop.strikeRate.toFixed(1)}</span>
            </div>
          </div>
        )}
        {teamBTop && (
          <div className="top-player">
            <p className="player-name">{teamBTop.name}</p>
            <div className="player-mini-stats">
              <span>{teamBTop.runs} runs</span>
              <span>SR: {teamBTop.strikeRate.toFixed(1)}</span>
            </div>
          </div>
        )}
      </div>

      <Link to={`/matches/${match._id}`} className="button-link">View Full Details</Link>
    </div>
  );
}

export default MatchCard;
